      return new Response(JSON.stringify({ error: "metrics must be an array" }), { status: 400, headers });
    }

    if (typeof body.thresholds!== "object" || Array.isArray(body.thresholds) || Object.keys(body.thresholds).length === 0) {
      return new Response(JSON.stringify({ error: "thresholds must be a non-empty object" }), { status: 400, headers });
    }

    const alerts: any[] = [];
    const summary = { total: 0, critical: 0, warn: 0, ok: 0, unknown: 0 };
    let worstStatusPriority = -1;
    let worstMetricName: string | null = null;

    for (const metric of body.metrics) {
      const name = metric.name;
      const value = metric.value;
      const threshold = body.thresholds[name];

      let status: string;
      let thresholdValue: number | null = null;

      if (threshold) {
        if (value > threshold.critical) {
          status = "critical";
          thresholdValue = threshold.critical;
        } else if (value > threshold.warn) {
          status = "warn";
          thresholdValue = threshold.warn;
        } else {
          status = "ok";
        }
      } else {
        status = "unknown";
      }

      alerts.push({ name, value, status, threshold: thresholdValue });

      summary.total++;
      summary[status] = (summary[status] as number) + 1;

      const currentPriority = getStatusPriority(status);
      if (currentPriority > worstStatusPriority) {
        worstStatusPriority = currentPriority;
        worstMetricName = name;
      } else if (currentPriority === worstStatusPriority &&!worstMetricName) {
        worstMetricName = name;
      }
    }

    worstMetricName = worstMetricName || "";

    return new Response(
      JSON.stringify({
        alerts,
        summary,
        worst: worstMetricName,
      }),
      { headers }
    );
  } catch (error) {
    console.error(error);
    return new Response(
      JSON.stringify({ error: "Internal Server Error" }),
      { status: 500, headers }
    );
  }
};

function getStatusPriority(status: string): number {
  switch (status) {
    case "critical":
      return 3;
    case "warn":
      return 2;
    case "unknown":
      return 1;
    default:
      return 0;
  }
}

