import { serve } from "https://deno.land/std@0.224.0/http/server.ts";

interface Metric {
  name: string;
  value: number;
  timestamp: string;
}

interface Threshold {
  warn: number;
  critical: number;
}

interface Thresholds {
  [metricName: string]: Threshold;
}

interface Alert {
  name: string;
  value: number;
  status: string;
  threshold: number | null;
}

interface Summary {
  total: number;
  critical: number;
  warn: number;
  ok: number;
  unknown: number;
}

interface ResponseBody {
  alerts: Alert[];
  summary: Summary;
  worst: string;
}

const STATUS_ORDER = ["critical", "warn", "unknown", "ok"];

function getWorstStatus(statuses: string[]): string {
  for (const status of STATUS_ORDER) {
    if (statuses.includes(status)) {
      return status;
    }
  }
  return "ok";
}

function handler(req: Request): Response {
  const headers = new Headers({
    "Content-Type": "application/json",
    "Access-Control-Allow-Origin": "*",
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type",
  });

  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204, headers });
  }

  if (req.method !== "POST") {
    return new Response(
      JSON.stringify({ error: "Method not allowed" }),
      { status: 405, headers }
    );
  }

  let body: { metrics?: unknown; thresholds?: unknown };

  try {
    const rawBody = req.body ? JSON.parse(req.body.toString()) : null;
    if (!rawBody) {
      return new Response(
        JSON.stringify({ error: "Empty body" }),
        { status: 400, headers }
      );
    }
    body = rawBody;
  } catch {
    return new Response(
      JSON.stringify({ error: "Invalid JSON" }),
      { status: 400, headers }
    );
  }

  if (!body.metrics || !Array.isArray(body.metrics)) {
    return new Response(
      JSON.stringify({ error: "metrics must be an array" }),
      { status: 400, headers }
    );
  }

  if (!body.thresholds || typeof body.thresholds !== "object" || Array.isArray(body.thresholds)) {
    return new Response(
      JSON.stringify({ error: "thresholds must be an object" }),
      { status: 400, headers }
    );
  }

  const metrics = body.metrics as Metric[];
  const thresholds = body.thresholds as Thresholds;

  const alerts: Alert[] = [];
  const statuses: string[] = [];

  for (const metric of metrics) {
    const threshold = thresholds[metric.name];
    let status: string;
    let thresholdValue: number | null = null;

    if (!threshold) {
      status = "unknown";
    } else if (metric.value > threshold.critical) {
      status = "critical";
      thresholdValue = threshold.critical;
    } else if (metric.value > threshold.warn) {
      status = "warn";
      thresholdValue = threshold.warn;
    } else {
      status = "ok";
      thresholdValue = threshold.warn;
    }

    statuses.push(status);

    alerts.push({
      name: metric.name,
      value: metric.value,
      status,
      threshold: thresholdValue,
    });
  }

  const summary: Summary = {
    total: metrics.length,
    critical: statuses.filter((s) => s === "critical").length,
    warn: statuses.filter((s) => s === "warn").length,
    ok: statuses.filter((s) => s === "ok").length,
    unknown: statuses.filter((s) => s === "unknown").length,
  };

  const worstStatus = getWorstStatus(statuses);
  const worstMetric = alerts.find((a) => a.status === worstStatus)?.name || "";

  const responseBody: ResponseBody = {
    alerts,
    summary,
    worst: worstMetric,
  };

  return new Response(JSON.stringify(responseBody), {
    status: 200,
    headers,
  });
}

